function usePersisted(key, initial) {
  const [state, setState] = useState(() => {
    try { const raw = localStorage.getItem(key); return raw ? JSON.parse(raw) : initial; } catch { return initial; }
  });
  useEffect(() => { try { localStorage.setItem(key, JSON.stringify(state)); } catch {} }, [key, state]);
  return [state, setState];
}
function useInter() {
  useEffect(() => {
    if (document.getElementById("alamo-inter")) return;
    const l = document.createElement("link"); l.id = "alamo-inter"; l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap";
    document.head.appendChild(l);
    const s = document.createElement("style");
    s.textContent = "body{font-family:'Inter',ui-sans-serif,system-ui,-apple-system,sans-serif;background:#F6F7F8}@media print{body *{visibility:hidden!important}#etiqueta-print,#etiqueta-print *{visibility:visible!important}#etiqueta-print{position:fixed;left:0;top:0;width:340px}}";
    document.head.appendChild(s);
  }, []);
}

