const ETAPAS = ["Impresión", "Tubado", "Fondo", "Cosido", "Terminado"];
const MAQUINA_ETAPA = { "Impresión": "Impresora Flexo IF-1", "Tubado": "Tubadora T-1", "Fondo": "Fondera F-2", "Cosido": "Cosedora C-1" };
const ANIO = new Date().getFullYear();

function liquidar(e) {
  const antigYears = Math.max(0, ANIO - e.ingreso);
  const antiguedad = e.basico * 0.01 * antigYears;
  const tienePresentismo = e.p.ausInjust === 0 && e.p.tardanzas <= 1;
  const presentismo = tienePresentismo ? e.basico * 0.0833 : 0;
  const bruto = e.basico + antiguedad + presentismo;
  const aportes = bruto * 0.17;
  return { antigYears, antiguedad, tienePresentismo, presentismo, bruto, aportes, neto: bruto - aportes };
}

/* Estado de entrega con alertas */
function estadoEntrega(p) {
  if (p.estado === "Entregado") return { label: "Entregado", c: "#047857", b: "#ECFDF5" };
  const fe = fechaEntrega(p);
  if (!fe) return { label: "Sin fecha", c: "#64748B", b: "#F1F5F9" };
  const dr = diasEntre(hoyISO(), fe);
  if (dr < 0) return { label: `Atrasado ${-dr}d`, c: "#B91C1C", b: "#FEF2F2", alerta: true };
  if (dr <= 3) return { label: `Vence en ${dr}d`, c: "#B45309", b: "#FFF7ED", alerta: true };
  return { label: `${dr}d restantes`, c: "#0369A1", b: "#EFF6FF" };
}

/* Costo directo de materiales por bolsa */
function costoMateriales(p, insumos) {
  const papel = insumos.find((i) => i.id === p.papelId);
  const tinta = insumos.find((i) => i.id === p.tintaId);
  const hilo = insumos.find((i) => i.id === p.hiloId);
  const cola = insumos.find((i) => i.categoria === "Cola");
  const valvula = insumos.find((i) => i.categoria === "Válvula");
  const areaM2 = ((p.ancho + p.fuelle) * 2 * (p.alto + 6)) / 10000 * 1.12;
  const pesoKg = (areaM2 * p.gramaje) / 1000;
  const cPapel = papel ? pesoKg * papel.costo : 0;
  const cTinta = tinta ? (p.colores * 0.35 / 1000) * tinta.costo : 0;
  const esCosida = p.tipoBolsa.toLowerCase().includes("cosida");
  const cHilo = esCosida && hilo ? hilo.costo / 2500 : 0;
  const cCola = !esCosida && cola ? cola.costo * 0.002 : 0;
  const cValv = p.tipoBolsa.toLowerCase().includes("valvulada") && valvula ? valvula.costo : 0;
  const detalle = [
    { k: "Papel", nombre: papel?.detalle || "—", v: cPapel },
    { k: "Tinta", nombre: (tinta?.detalle || "—") + ` × ${p.colores} color`, v: cTinta },
    { k: esCosida ? "Hilo" : "Cola", nombre: esCosida ? (hilo?.detalle || "—") : (cola?.detalle || "—"), v: esCosida ? cHilo : cCola },
    { k: "Válvula", nombre: valvula?.detalle || "—", v: cValv },
  ];
  return { pesoKg, total: cPapel + cTinta + cHilo + cCola + cValv, detalle };
}

/* --------- Código de barras Code 39 (autocontenido, escaneable) --------- */
const C39 = { "0": "nnnwwnwnn", "1": "wnnwnnnnw", "2": "nnwwnnnnw", "3": "wnwwnnnnn", "4": "nnnwwnnnw", "5": "wnnwwnnnn", "6": "nnwwwnnnn", "7": "nnnwnnwnw", "8": "wnnwnnwnn", "9": "nnwwnnwnn", "A": "wnnnnwnnw", "B": "nnwnnwnnw", "C": "wnwnnwnnn", "D": "nnnnwwnnw", "E": "wnnnwwnnn", "F": "nnwnwwnnn", "G": "nnnnnwwnw", "H": "wnnnnwwnn", "I": "nnwnnwwnn", "J": "nnnnwwwnn", "K": "wnnnnnnww", "L": "nnwnnnnww", "M": "wnwnnnnwn", "N": "nnnnwnnww", "O": "wnnnwnnwn", "P": "nnwnwnnwn", "Q": "nnnnnnwww", "R": "wnnnnnwwn", "S": "nnwnnnwwn", "T": "nnnnwnwwn", "U": "wwnnnnnnw", "V": "nwwnnnnnw", "W": "wwwnnnnnn", "X": "nwnnwnnnw", "Y": "wwnnwnnnn", "Z": "nwwnwnnnn", "-": "nwnnnnwnw", ".": "wwnnnnwnn", " ": "nwwnnnwnn", "*": "nwnnwnwnn" };
function Barcode({ value, height = 52 }) {
  const text = String(value).toUpperCase().replace(/[^0-9A-Z\-\. ]/g, "");
  const code = "*" + text + "*";
  const N = 2, W = 5, gap = 2;
  const rects = []; let x = 0;
  for (let ci = 0; ci < code.length; ci++) {
    const pat = C39[code[ci]]; if (!pat) continue;
    for (let i = 0; i < 9; i++) {
      const w = pat[i] === "w" ? W : N;
      if (i % 2 === 0) rects.push(<rect key={ci + "-" + i} x={x} y={0} width={w} height={height} fill="#1A2230" />);
      x += w;
    }
    x += gap;
  }
  return (
    <div className="text-center">
      <svg viewBox={`0 0 ${x} ${height}`} width="100%" style={{ maxWidth: 320, height }} preserveAspectRatio="xMidYMid meet">{rects}</svg>
      <div className="font-mono text-xs tracking-[0.25em] mt-1" style={{ color: INK }}>{text}</div>
    </div>
  );
}

const PIE_COLORS = ["#5F7D24", "#A4C24E", "#0369A1", "#B45309", "#7C3AED", "#0D9488", "#DB2777", "#64748B"];

function QR({ text, size = 150 }) {
  const [url, setUrl] = useState("");
  useEffect(() => {
    let ok = true;
    QRCode.toDataURL(text || " ", { margin: 1, width: size * 2, color: { dark: "#1A2230", light: "#ffffff" } })
      .then((u) => { if (ok) setUrl(u); }).catch(() => {});
    return () => { ok = false; };
  }, [text, size]);
  return url ? <img src={url} alt="QR" style={{ width: size, height: size }} /> : <div style={{ width: size, height: size }} className="bg-slate-100 rounded" />;
}

function EtiquetaModal({ titulo, lineas, code, onClose }) {
  const qrText = ["ALAMO", titulo, ...lineas, "Cod: " + code].join("\n");
  return (
    <Modal title="Etiqueta · QR y código de barras" onClose={onClose}>
      <div id="etiqueta-print" className="border rounded-[12px] p-5" style={{ borderColor: BORDER }}>
        <div className="flex items-center gap-2 mb-3"><img src={LOGO} alt="Álamo" className="h-7" /></div>
        <div className="text-sm font-semibold mb-1" style={{ color: INK }}>{titulo}</div>
        {lineas.map((l, i) => <div key={i} className="text-xs text-slate-500">{l}</div>)}
        <div className="flex items-center gap-4 mt-4 flex-wrap sm:flex-nowrap">
          <div className="shrink-0"><QR text={qrText} size={140} /></div>
          <div className="flex-1 min-w-[180px]"><Barcode value={code} /></div>
        </div>
        <div className="text-[10px] text-slate-400 mt-2">Mismo código en la orden de pedido y en el producto terminado · trazabilidad de punta a punta.</div>
      </div>
      <div className="flex justify-end gap-2 mt-4">
        <button onClick={onClose} className="text-sm font-medium px-4 py-2.5 rounded-[10px] border" style={{ borderColor: BORDER, color: "#64748B" }}>Cerrar</button>
        <BtnPrimary onClick={() => window.print()}><Printer size={16} /> Imprimir</BtnPrimary>
      </div>
    </Modal>
  );
}

